const offre = $('France Travail - Offres').item.json.resultats[0];

const titre = (offre.intitule || "").toLowerCase();
const description = (offre.description || "").toLowerCase();
const typeContrat = (offre.typeContrat || "").toLowerCase();
const typeContratLibelle = (offre.typeContratLibelle || "").toLowerCase();
const alternanceApi = offre.alternance === true;

const motsCles = [
  "devops",
  "linux",
  "docker",
  "kubernetes",
  "k8s",
  "terraform",
  "ansible",
  "gitlab",
  "github actions",
  "ci/cd",
  "aws",
  "azure",
  "gcp",
  "cloud"
];

const motsClesAlternance = [
  "alternance",
  "apprentissage",
  "contrat apprentissage",
  "professionnalisation",
  "contrat pro",
  "stage"
];

const texteGlobal = `${titre} ${description} ${typeContrat} ${typeContratLibelle}`;

const motsTrouves = motsCles.filter(mot =>
  texteGlobal.includes(mot.toLowerCase())
);

const motsAlternanceTrouves = motsClesAlternance.filter(mot =>
  texteGlobal.includes(mot.toLowerCase())
);

const alternanceDetectee =
  alternanceApi ||
  motsAlternanceTrouves.length > 0;

return [
  {
    json: {
      titre: offre.intitule,
      contrat: offre.typeContrat,
      contrat_libelle: offre.typeContratLibelle,
      alternance_api: alternanceApi,
      mots_cles_trouves: motsTrouves,
      nombre_mots_cles: motsTrouves.length,
      mots_alternance_trouves: motsAlternanceTrouves,
      alternance_detectee: alternanceDetectee
    }
  }
];

const pages = $input.all();

let toutesLesOffres = [];

for (const page of pages) {
  const offresPage = page.json.resultats || page.json.results || [];
  toutesLesOffres.push(...offresPage);
}

const vus = new Set();
const offresUniques = [];
const doublons = [];

for (const offre of toutesLesOffres) {
  const id = offre.id || '';
  const url = offre.origineOffre?.urlOrigine || '';
  const cle = id || url;

  if (!cle) continue;

  if (vus.has(cle)) {
    doublons.push({
      id,
      url,
      intitule: offre.intitule || ''
    });
  } else {
    vus.add(cle);
    offresUniques.push(offre);
  }
}

return [
  {
    json: {
      nombre_pages: pages.length,
      nombre_initial: toutesLesOffres.length,
      nombre_uniques: offresUniques.length,
      doublons_supprimes: doublons.length,
      ids_uniques: offresUniques.map(o => o.id),
      offres_uniques: offresUniques
    }
  }
];

const offre = $('France Travail - Offres').item.json.resultats[0];

const texte =
`${offre.intitule}
${offre.description}
${offre.typeContrat}
${offre.typeContratLibelle}`.toLowerCase();

let score = 0;

const devops = [
  "devops",
  "gitlab",
  "github actions",
  "jenkins",
  "terraform",
  "ansible",
  "ci/cd",
  "linux"
];

const cloud = [
  "aws",
  "azure",
  "gcp",
  "cloud"
];

const kubernetes = [
  "kubernetes",
  "k8s",
  "helm",
  "openshift",
  "eks",
  "aks"
];

const docker = [
  "docker",
  "container",
  "containers",
  "podman"
];

const alternance = [
  "alternance",
  "apprentissage",
  "contrat pro",
  "professionnalisation"
];

if (devops.some(m => texte.includes(m))) score += 40;
if (cloud.some(m => texte.includes(m))) score += 20;
if (kubernetes.some(m => texte.includes(m))) score += 15;
if (docker.some(m => texte.includes(m))) score += 15;
if (alternance.some(m => texte.includes(m))) score += 10;

return [
  {
    json: {
      titre: offre.intitule,
      score_pertinence: score
    }
  }
];

const offres = $json.offres_uniques || [];

const offresTriees = offres.sort((a, b) => {
  const dateA = new Date(a.dateCreation || 0);
  const dateB = new Date(b.dateCreation || 0);

  return dateB - dateA;
});

return [
  {
    json: {
      nombre_total: offresTriees.length,
      offres_triees: offresTriees
    }
  }
];

const offresTriees = $('Tri Offres').item.json.offres_triees || [];

const limite = 3000;

const topOffres = offresTriees.slice(0, limite);

return [
  {
    json: {
      limite,
      nombre_total: offresTriees.length,
      nombre_selectionne: topOffres.length,
      top_offres: topOffres
    }
  }
];

const item = $json;

const raw = item.response || '';
const model = item.model || item.modele_ia || 'unknown';
const done = item.done ?? false;
const doneReason = item.done_reason || null;

let cleaned = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

// Corrige les objets bizarres du type {"Bash"} => "Bash"
cleaned = cleaned.replace(/\{\s*"([^"]+)"\s*\}/g, '"$1"');

let parsed = {};
let erreur_ia = false;
let type_erreur_ia = null;
let message_erreur_ia = null;

if (!raw || raw.trim() === '') {
  erreur_ia = true;
  type_erreur_ia = 'REPONSE_VIDE';
  message_erreur_ia = 'La réponse Ollama est vide.';
}

if (!erreur_ia) {
  try {
    const firstBrace = cleaned.indexOf('{');
    const lastBrace = cleaned.lastIndexOf('}');

    if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
      cleaned = cleaned.slice(firstBrace, lastBrace + 1);
    }

    parsed = JSON.parse(cleaned);
  } catch (error) {
    erreur_ia = true;
    type_erreur_ia = 'JSON_INVALIDE';
    message_erreur_ia = error.message;

    parsed = {
      resume: cleaned,
      score_ia: 0,
      competences_detectees: [],
      points_forts: [],
      points_faibles: ['Réponse IA non JSON ou JSON invalide'],
      recommandation: 'Parser à corriger ou modèle IA à changer',
      classement: 'Erreur IA'
    };
  }
}

const competences =
  parsed.competences_detectees ||
  parsed.skills_detectees ||
  parsed['.skills_detectees'] ||
  [];

const recommandation =
  parsed.recommandation ||
  parsed.recommandations ||
  '';

return {
  json: {
    ...item,

    erreur_ia,
    type_erreur_ia,
    message_erreur_ia,

    resume: parsed.resume || '',
    score_ia: Number(parsed.score_ia) || 0,
    competences_detectees: Array.isArray(competences)
      ? competences.flat().map(String)
      : [],
    points_forts: Array.isArray(parsed.points_forts)
      ? parsed.points_forts.flat().map(String)
      : [],
    points_faibles: Array.isArray(parsed.points_faibles)
      ? parsed.points_faibles.flat().map(String)
      : [],
    recommandation: Array.isArray(recommandation)
      ? recommandation.join(', ')
      : String(recommandation || ''),
    classement: String(parsed.classement || ''),

    modele_ia: model,
    done,
    done_reason: doneReason
  }
};

const offre = $json;

let score_contrat = 0;
let score_experience = 0;
let score_diplome = 0;
let score_metier = 0;

const texte = `
${offre.titre || ''}
${offre.type_contrat_libelle || ''}
${offre.contrat || ''}
${offre.experience || ''}
${offre.description || ''}
`.toLowerCase();


// ========================================
// FLAGS IMPORTANTS POUR CSV / BASE
// ========================================

const debutant_accepte =
  texte.includes('débutant accepté') ||
  texte.includes('debutant accepte') ||
  texte.includes('débutant') ||
  texte.includes('debutant') ||
  texte.includes('junior');

const contrat_professionnalisation =
  texte.includes('professionnalisation') ||
  texte.includes('contrat pro') ||
  texte.includes('contrat de professionnalisation');

const contrat_apprentissage =
  texte.includes('apprentissage') ||
  texte.includes('contrat apprentissage') ||
  texte.includes('contrat d’apprentissage') ||
  texte.includes("contrat d'apprentissage");


// ========================================
// CONTRAT
// ========================================

if (texte.includes('alternance')) score_contrat += 40;
if (contrat_apprentissage) score_contrat += 40;
if (contrat_professionnalisation) score_contrat += 40;

if (texte.includes('cdd')) score_contrat += 10;

if (texte.includes('cdi')) score_contrat -= 20;


// ========================================
// EXPERIENCE
// ========================================

if (debutant_accepte) {
  score_experience += 40;
}
else if (
  texte.includes('1 an') ||
  texte.includes('12 mois')
) {
  score_experience += 20;
}
else if (texte.includes('2 an')) {
  score_experience -= 10;
}
else if (texte.includes('3 an')) {
  score_experience -= 30;
}
else if (
  texte.includes('4 an') ||
  texte.includes('5 an') ||
  texte.includes('10 an')
) {
  score_experience -= 60;
}


// ========================================
// DIPLOME
// ========================================

if (texte.includes('bac+2') || texte.includes('bac +2')) score_diplome += 20;

if (
  texte.includes('bac+3') ||
  texte.includes('bac +3') ||
  texte.includes('bachelor')
) {
  score_diplome += 20;
}

if (
  texte.includes('bac+5') ||
  texte.includes('bac +5') ||
  texte.includes('ingénieur') ||
  texte.includes('ingenieur')
) {
  score_diplome -= 20;
}


// ========================================
// METIER
// ========================================

if (
  texte.includes('devops') ||
  texte.includes('cloud') ||
  texte.includes('sre') ||
  texte.includes('linux') ||
  texte.includes('docker') ||
  texte.includes('kubernetes') ||
  texte.includes('terraform') ||
  texte.includes('administrateur système') ||
  texte.includes('administrateur reseau') ||
  texte.includes('administrateur réseau') ||
  texte.includes('systèmes et réseaux') ||
  texte.includes('systemes et reseaux') ||
  texte.includes('support informatique') ||
  texte.includes('technicien informatique') ||
  texte.includes('développeur') ||
  texte.includes('developpeur') ||
  texte.includes('developer') ||
  texte.includes('backend') ||
  texte.includes('fullstack') ||
  texte.includes('data analyst') ||
  texte.includes('data engineer') ||
  texte.includes('data scientist') ||
  texte.includes('ai engineer') ||
  texte.includes('intelligence artificielle')
) {
  score_metier += 20;
}

if (
  texte.includes('vendeur') ||
  texte.includes('vente') ||
  texte.includes('commercial') ||
  texte.includes('caissier') ||
  texte.includes('caissière') ||
  texte.includes('conseiller de vente') ||
  texte.includes('magasin') ||
  texte.includes('opérateur de saisie') ||
  texte.includes('operateur de saisie') ||
  texte.includes('saisie informatique') ||
  texte.includes('gestionnaire de saisie') ||
  texte.includes('relation client') ||
  texte.includes('bureautique') ||
  texte.includes('flottes automobiles') ||
  texte.includes('appels entrants') ||
  texte.includes('rendez-vous') ||
  texte.includes('excel') ||
  texte.includes('word')
) {
  score_metier -= 60;
}

if (
  texte.includes('directeur') ||
  texte.includes('dirigeant') ||
  texte.includes('responsable de département') ||
  texte.includes('head of') ||
  texte.includes('manager senior')
) {
  score_metier -= 80;
}


// ========================================
// SCORE REGLES
// ========================================

let score_regles =
  50 +
  score_contrat +
  score_experience +
  score_diplome +
  score_metier;

if (score_regles > 100) score_regles = 100;
if (score_regles < 0) score_regles = 0;


// ========================================
// CLASSEMENT REGLES
// ========================================

let classement = '';

if (score_regles >= 80) {
  classement = 'Tres pertinent';
}
else if (score_regles >= 60) {
  classement = 'Pertinent';
}
else if (score_regles >= 40) {
  classement = 'Moyen';
}
else {
  classement = 'Faible';
}


// ========================================
// RETURN
// ========================================

return {
  json: {
    ...offre,
    debutant_accepte,
    contrat_professionnalisation,
    contrat_apprentissage,
    score_contrat,
    score_experience,
    score_diplome,
    score_metier,
    score_regles,
    classement
  }
};

const offre = $json;

let score_ia = Number(offre.score_ia) || 0;

// Si l'IA renvoie 0.85 au lieu de 85
if (score_ia > 0 && score_ia <= 1) {
  score_ia = Math.round(score_ia * 100);
}

const score_regles = Number(offre.score_regles) || 0;

let score_final;

// Si l'IA ne donne pas de score fiable, on garde le score règles
if (score_ia <= 0) {
  score_final = score_regles;
} else {
  // 70% règles fiables + 30% IA
  score_final = Math.round((score_regles * 0.7) + (score_ia * 0.3));
}

if (score_final > 100) score_final = 100;
if (score_final < 0) score_final = 0;

return {
  json: {
    ...offre,
    score_ia,
    score_final
  }
};

const offre = $json;

let classement = '';

if (offre.score_final >= 80) {
  classement = 'Très pertinent';
}
else if (offre.score_final >= 60) {
  classement = 'Pertinent';
}
else if (offre.score_final >= 40) {
  classement = 'Moyen';
}
else {
  classement = 'Faible';
}

return {
  json: {
    ...offre,
    classement_final: classement
  }
};

const lettre = ($json.response || '').trim();

return {
  json: {
    ...$json,
    lettre_brouillon: lettre
  }
};

const data = $json;

const prompt = data.prompt_utilise || '';
const lettre = data.reponse_ia || data.lettre_brouillon || 'Lettre non disponible.';
const url = $('Merge LM').item.json.url || '#';

function extractBetween(startLabel, endLabel) {
  const start = prompt.indexOf(startLabel);
  if (start === -1) return '';
  const contentStart = start + startLabel.length;
  const end = endLabel ? prompt.indexOf(endLabel, contentStart) : -1;

  return prompt
    .slice(contentStart, end === -1 ? undefined : end)
    .trim();
}

function clean(value, fallback) {
  return (value || '').trim() || fallback;
}

const entreprise = clean(
  data.entreprise || extractBetween('Entreprise :', 'Poste :'),
  'Entreprise non précisée'
);

const titre = clean(
  data.titre || extractBetween('Poste :', 'Ville :'),
  'Offre sans titre'
);

const ville = clean(
  data.ville || data.lieu || extractBetween('Ville :', 'Contrat :'),
  'Ville non précisée'
);

const contrat = clean(
  data.contrat || data.type_contrat_libelle || extractBetween('Contrat :', 'Expérience demandée :'),
  'Contrat non précisé'
);

const experience = clean(
  data.experience || extractBetween('Expérience demandée :', 'Description :'),
  'Expérience non précisée'
);

const description = clean(
  data.description || extractBetween('Description :', '====================================================\nPROFIL CANDIDAT'),
  'Description non disponible'
);

const scoreFinal = data.score_final ?? 'N/A';

let classement = data.classement_final || 'Non classé';

if (!data.classement_final && typeof data.score_final === 'number') {
  if (data.score_final >= 90) classement = 'Très pertinent';
  else if (data.score_final >= 60) classement = 'Pertinent';
  else if (data.score_final >= 40) classement = 'Moyen';
  else classement = 'Faible';
}

const dateAnalyse =
new Date(
  data.date_generation ||
  new Date()
).toLocaleString('fr-FR');

const emailSubject = `Nouvelle offre pertinente — ${titre} — Score ${scoreFinal}/100`;

const emailHtml = `
<div style="font-family: Arial, sans-serif; line-height: 1.5; color: #222;">
  <h2>Nouvelle offre pertinente détectée</h2>

  <h3>1. Offre</h3>
  <p>
    <strong>Poste :</strong> ${titre}<br>
    <strong>Entreprise :</strong> ${entreprise}<br>
    <strong>Ville :</strong> ${ville}<br>
    <strong>Contrat :</strong> ${contrat}<br>
    <strong>Expérience :</strong> ${experience}
  </p>

  <h3>2. Score IA</h3>

  <div style="
    padding:12px;
    background:#e8f5e9;
    border:1px solid #4caf50;
    border-radius:6px;
    font-size:18px;
  ">
    <strong>Score :</strong> ${scoreFinal}/100
    <br><br>
    <strong>Classement :</strong> ${classement}
  </div>

  <h3>3. Résumé offre</h3>
  <div style="border-left:4px solid #ccc; padding-left:12px; white-space:pre-line;">
${description.slice(0, 800)}
  </div>

  <h3>4. Lettre de motivation générée</h3>
  <div style="border:1px solid #ddd; padding:12px; background:#f9f9f9; white-space:pre-line;">
${lettre}
  </div>

  <h3>5. Lien offre</h3>
  <p>
    <a href="${url}" target="_blank">Ouvrir l'offre France Travail</a>
  </p>

  <h3>6. Date analyse</h3>
  <p>${dateAnalyse}</p>
</div>
`;

return {
  json: {
    ...data,
    titre,
    entreprise,
    ville,
    contrat,
    experience,
    url,
    classement_final: classement,
    lettre_brouillon: lettre,
    email_subject: emailSubject,
    email_html: emailHtml
  }
};

let qualite = 'BONNE';

if ($json.statut === 'ERREUR' || $json.type_erreur) {
  qualite = 'MAUVAISE';
} else if (($json.score_ia || 0) <= 0) {
  qualite = 'MOYENNE';
}

return {
  json: {
    ...$json,
    qualite_analyse: qualite
  }
};

const motsCles = 'informatique';

// Période exacte à collecter
const dateDebut = '2026-06-01';
const dateFin = '2026-06-04';

// Taille page France Travail
const pageSize = 150;

// Limite API France Travail : début max = 3000
const maxStart = 500;

function addDays(date, days) {
  const d = new Date(date);
  d.setDate(d.getDate() + days);
  return d;
}

function formatDate(date) {
  return date.toISOString().slice(0, 10);
}

const items = [];

let currentDate = new Date(`${dateDebut}T00:00:00Z`);
const endDate = new Date(`${dateFin}T00:00:00Z`);

while (currentDate <= endDate) {
  const jour = formatDate(currentDate);

  for (let start = 0; start <= maxStart; start += pageSize) {
    const end = start + pageSize - 1;

    // Sécurité : on ne dépasse pas 2999
    if (start >= 3000) break;

    items.push({
      json: {
        motsCles,
        range: `${start}-${end}`,
        minCreationDate: `${jour}T00:00:00Z`,
        maxCreationDate: `${jour}T23:59:59Z`
      }
    });
  }

  currentDate = addDays(currentDate, 1);
}

return items;
